import React, { useState, useEffect } from 'react';
import './App.css';
import FriendList from './components/FriendList';
import AddMeal from './components/AddMeal';
import BalanceView from './components/BalanceView';
import SettlementList from './components/SettlementList';
import MealHistory from './components/MealHistory';
import api from './services/api';

function App() {
  const [activeTab, setActiveTab] = useState('add');
  const [refreshTrigger, setRefreshTrigger] = useState(0);
  const [friends, setFriends] = useState([]);

  const refreshData = () => {
    setRefreshTrigger(prev => prev + 1);
  };

  useEffect(() => {
    loadFriends();
  }, [refreshTrigger]);

  const loadFriends = async () => {
    try {
      const data = await api.getFriends();
      setFriends(data);
    } catch (error) {
      console.error('Error loading friends:', error);
    }
  };

  return (
    <div className="app">
      <header className="header">
        <h1>🍽️ Meal Share Tracker</h1>
        <p>Track meals with friends, split bills easily</p>
      </header>

      <div className="tabs">
        <button className={activeTab === 'add' ? 'tab active' : 'tab'} onClick={() => setActiveTab('add')}>
          ➕ Add Meal
        </button>
        <button className={activeTab === 'balance' ? 'tab active' : 'tab'} onClick={() => setActiveTab('balance')}>
          💰 Balances
        </button>
        <button className={activeTab === 'history' ? 'tab active' : 'tab'} onClick={() => setActiveTab('history')}>
          📜 Meal History
        </button>
        <button className={activeTab === 'friends' ? 'tab active' : 'tab'} onClick={() => setActiveTab('friends')}>
          👥 Friends
        </button>
        <button className={activeTab === 'settlements' ? 'tab active' : 'tab'} onClick={() => setActiveTab('settlements')}>
          ✅ Settlements
        </button>
      </div>

      <div className="content">
        {activeTab === 'add' && <AddMeal friends={friends} onMealAdded={refreshData} />}
        {activeTab === 'balance' && <BalanceView refreshTrigger={refreshTrigger} onSettlementMade={refreshData} />}
        {activeTab === 'history' && <MealHistory refreshTrigger={refreshTrigger} onDelete={refreshData} />}
        {activeTab === 'friends' && <FriendList friends={friends} onFriendChange={refreshData} />}
        {activeTab === 'settlements' && <SettlementList refreshTrigger={refreshTrigger} onConfirm={refreshData} />}
      </div>
    </div>
  );
}

export default App;
